function App() {
  const [search, setSearch] = React.useState('');
  const [filters, setFilters] = React.useState({ climate: 'all', budget: 'all' });
  const [wishlist, setWishlist] = React.useState([1]);
  const [selected, setSelected] = React.useState(null);

  const destinations = [
    { id: 1, name: 'Kyoto, Japan', country: 'Japan', emoji: '⛩️', rating: 4.8, reviews: 2341, avgCost: 2500, climate: 'temperate', tags: ['culture', 'temples', 'food'], desc: 'Ancient temples, bamboo groves, and world-class cuisine.' },
    { id: 2, name: 'Barcelona, Spain', country: 'Spain', emoji: '🏛️', rating: 4.7, reviews: 3892, avgCost: 2000, climate: 'mediterranean', tags: ['beach', 'art', 'nightlife'], desc: 'Gaudí architecture, beaches, and vibrant city life.' },
    { id: 3, name: 'Queenstown, NZ', country: 'New Zealand', emoji: '🏔️', rating: 4.9, reviews: 1567, avgCost: 3200, climate: 'temperate', tags: ['adventure', 'nature', 'skiing'], desc: 'Adventure capital with stunning mountain scenery.' },
    { id: 4, name: 'Bali, Indonesia', country: 'Indonesia', emoji: '🌺', rating: 4.6, reviews: 4211, avgCost: 1500, climate: 'tropical', tags: ['beach', 'culture', 'wellness'], desc: 'Spiritual retreats, rice terraces, and ocean sunsets.' },
  ];

  const filtered = destinations.filter(d =>
    (search === '' || d.name.toLowerCase().includes(search.toLowerCase())) &&
    (filters.climate === 'all' || d.climate === filters.climate) &&
    (filters.budget === 'all' || (filters.budget === 'budget' ? d.avgCost < 2000 : filters.budget === 'mid' ? d.avgCost < 3000 : d.avgCost >= 3000))
  );

  const toggleWishlist = (id) => setWishlist(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);

  const colors1 = ['#dbeafe', '#fce7f3', '#dcfce7', '#fef9c3'];
  const colors2 = ['#ede9fe', '#fee2e2', '#d1fae5', '#ffedd5'];

  return (
    <div className="min-h-screen bg-slate-50 max-w-[390px] mx-auto font-sans">
      {/* Header */}
      <div data-dg-component="searchBar" className="bg-gradient-to-br from-sky-500 to-indigo-500 px-5 pt-5 pb-6">
        <div className="text-[13px] text-white/70 mb-1">Where to next?</div>
        <div className="text-2xl font-extrabold text-white mb-4">Discover Destinations</div>
        <div className="flex items-center bg-white rounded-[14px] px-4 py-[11px] gap-2.5">
          <span className="text-lg">🔍</span>
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search destinations..." className="border-none outline-none text-sm flex-1 text-gray-700 bg-transparent" />
          {search && <button onClick={() => setSearch('')} className="bg-transparent border-none text-base cursor-pointer text-slate-400">✕</button>}
        </div>
      </div>

      {/* Filters */}
      <div data-dg-component="destinationFilters" className="flex gap-2 px-4 py-3.5 overflow-x-auto">
        <select value={filters.climate} onChange={e => setFilters(p => ({ ...p, climate: e.target.value }))}
          className="shrink-0 border-[1.5px] border-slate-200 rounded-full px-3.5 py-[7px] text-xs text-gray-700 bg-white cursor-pointer outline-none font-semibold">
          <option value="all">🌍 All Climates</option>
          <option value="temperate">🌤 Temperate</option>
          <option value="mediterranean">☀️ Mediterranean</option>
          <option value="tropical">🌴 Tropical</option>
        </select>
        <select value={filters.budget} onChange={e => setFilters(p => ({ ...p, budget: e.target.value }))}
          className="shrink-0 border-[1.5px] border-slate-200 rounded-full px-3.5 py-[7px] text-xs text-gray-700 bg-white cursor-pointer outline-none font-semibold">
          <option value="all">💰 Any Budget</option>
          <option value="budget">💚 Under $2k</option>
          <option value="mid">💛 $2k–$3k</option>
          <option value="premium">❤️ $3k+</option>
        </select>
      </div>

      {/* Cards */}
      <div data-dg-component="destinationCards" className="px-4 pb-6">
        {filtered.map(dest => (
          <div key={dest.id} onClick={() => setSelected(selected === dest.id ? null : dest.id)}
            className={`bg-white rounded-[20px] mb-3.5 overflow-hidden cursor-pointer transition-shadow duration-200 ${selected === dest.id ? 'ring-2 ring-indigo-500' : 'shadow-sm'}`}>
            <div className="h-[110px] flex items-center justify-center text-[52px] relative"
              style={{ background: `linear-gradient(135deg, ${colors1[dest.id-1]}, ${colors2[dest.id-1]})` }}>
              {dest.emoji}
              <button data-dg-component="wishlistToggle" onClick={e => { e.stopPropagation(); toggleWishlist(dest.id); }}
                className="absolute top-3 right-3 bg-white border-none rounded-full w-8 h-8 text-base cursor-pointer shadow">
                {wishlist.includes(dest.id) ? '❤️' : '🤍'}
              </button>
            </div>
            <div className="px-4 py-3.5">
              <div className="flex justify-between items-start">
                <div>
                  <div className="text-base font-bold text-slate-900">{dest.name}</div>
                  <div className="text-xs text-slate-400 mt-0.5">⭐ {dest.rating} · {dest.reviews.toLocaleString()} reviews</div>
                </div>
                <div className="text-right">
                  <div className="text-[15px] font-bold text-slate-900">${dest.avgCost.toLocaleString()}</div>
                  <div className="text-[11px] text-slate-400">avg trip cost</div>
                </div>
              </div>
              {selected === dest.id && (
                <div data-dg-component="destinationDetail" className="mt-2.5">
                  <div className="text-[13px] text-slate-500 leading-relaxed">{dest.desc}</div>
                  <div className="flex gap-1.5 mt-2.5 flex-wrap">
                    {dest.tags.map(tag => <span key={tag} className="text-[11px] bg-slate-100 text-slate-500 px-2.5 py-[3px] rounded-full font-semibold">{tag}</span>)}
                  </div>
                  <button className="w-full mt-3 bg-gradient-to-br from-sky-500 to-indigo-500 text-white border-none rounded-xl py-3 text-sm font-bold cursor-pointer">
                    Plan a Trip →
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="text-center py-12 text-slate-400">
            <div className="text-[40px]">🗺️</div>
            <div className="text-[15px] font-semibold mt-3">No destinations found</div>
          </div>
        )}
      </div>
    </div>
  );
}

function App() {
  const [tab, setTab] = React.useState('itinerary');
  const [days, setDays] = React.useState([
    { day: 1, date: 'Apr 10', activities: ['Arrive Kyoto', 'Check-in hotel', 'Gion district walk'], budget: 200 },
    { day: 2, date: 'Apr 11', activities: ['Fushimi Inari hike', 'Nishiki Market lunch', 'Tea ceremony'], budget: 150 },
    { day: 3, date: 'Apr 12', activities: ['Arashiyama bamboo grove', 'Kinkakuji temple', 'Farewell dinner'], budget: 180 },
  ]);
  const [expenses, setExpenses] = React.useState([
    { id: 1, cat: '🏨', label: 'Hotel (3 nights)', amount: 540 },
    { id: 2, cat: '✈️', label: 'Flight tickets', amount: 680 },
    { id: 3, cat: '🎫', label: 'Activities & Entrance', amount: 125 },
    { id: 4, cat: '🍜', label: 'Food & Dining', amount: 210 },
  ]);
  const [newActivity, setNewActivity] = React.useState('');
  const [editDay, setEditDay] = React.useState(null);

  const totalBudget = 2000;
  const totalSpent = expenses.reduce((s, e) => s + e.amount, 0);
  const remaining = totalBudget - totalSpent;

  const addActivity = (dayIdx) => {
    if (!newActivity.trim()) return;
    setDays(prev => prev.map((d, i) => i === dayIdx ? { ...d, activities: [...d.activities, newActivity] } : d));
    setNewActivity('');
    setEditDay(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 max-w-[390px] mx-auto font-sans">
      {/* Header */}
      <div data-dg-component="tripHeader" className="bg-white border-b border-slate-100 px-5 pt-4 pb-0">
        <div className="flex items-center gap-2.5 mb-1">
          <span className="text-2xl">⛩️</span>
          <div>
            <div className="text-lg font-extrabold text-slate-900">Kyoto, Japan</div>
            <div className="text-xs text-slate-400">Apr 10 – 12 · 2 travelers</div>
          </div>
          <button data-dg-component="shareTrip" className="ml-auto bg-blue-50 text-blue-500 border-none rounded-[10px] px-3.5 py-2 text-xs font-bold cursor-pointer">Share 📤</button>
        </div>
        <div className="flex bg-slate-100 rounded-xl p-1 mt-3.5">
          {[['itinerary', '📅 Itinerary'], ['hotels', '🏨 Hotels'], ['budget', '💰 Budget']].map(([key, label]) => (
            <button key={key} onClick={() => setTab(key)}
              className={`flex-1 py-2 px-1 rounded-[9px] border-none cursor-pointer text-xs font-semibold transition-all duration-150 ${tab === key ? 'bg-white text-slate-900 shadow-sm' : 'bg-transparent text-slate-500'}`}>
              {label}
            </button>
          ))}
        </div>
        <div className="h-3.5" />
      </div>

      <div className="px-4 pt-4 pb-8">
        {/* Itinerary Tab */}
        {tab === 'itinerary' && days.map((d, idx) => (
          <div data-dg-component="itineraryDay" key={d.day} className="bg-white rounded-[18px] p-4 mb-3 shadow-sm">
            <div className="flex justify-between items-center mb-3">
              <div className="flex items-center gap-2.5">
                <div className="w-9 h-9 bg-gradient-to-br from-sky-500 to-indigo-500 rounded-[10px] flex items-center justify-center text-white font-extrabold text-sm">D{d.day}</div>
                <div>
                  <div className="text-sm font-bold text-slate-900">Day {d.day}</div>
                  <div className="text-xs text-slate-400">{d.date}</div>
                </div>
              </div>
              <div className="text-[13px] text-slate-500">${d.budget} budget</div>
            </div>
            {d.activities.map((a, ai) => (
              <div key={ai} className={`flex items-center gap-2.5 py-2 ${ai < d.activities.length - 1 ? 'border-b border-slate-100' : ''}`}>
                <div className="w-1.5 h-1.5 bg-sky-500 rounded-full shrink-0" />
                <div className="text-[13px] text-gray-700">{a}</div>
              </div>
            ))}
            {editDay === idx ? (
              <div className="flex gap-2 mt-2.5">
                <input value={newActivity} onChange={e => setNewActivity(e.target.value)} placeholder="Add activity..." autoFocus
                  className="flex-1 border-[1.5px] border-sky-500 rounded-[10px] px-3 py-2 text-[13px] outline-none"
                  onKeyDown={e => e.key === 'Enter' && addActivity(idx)} />
                <button onClick={() => addActivity(idx)} className="bg-sky-500 text-white border-none rounded-[10px] px-3.5 py-2 cursor-pointer font-bold">+</button>
              </div>
            ) : (
              <button onClick={() => setEditDay(idx)} className="mt-2.5 bg-transparent border-[1.5px] border-dashed border-slate-200 rounded-[10px] px-3.5 py-[7px] text-xs text-slate-400 cursor-pointer w-full">
                + Add activity
              </button>
            )}
          </div>
        ))}

        {/* Hotels Tab */}
        {tab === 'hotels' && [
          { name: 'Kyoto Grand Hotel', stars: 4, price: 180, avail: true, emoji: '🏯' },
          { name: 'Gion Ryokan', stars: 5, price: 320, avail: true, emoji: '🏠' },
          { name: 'Budget Inn Kyoto', stars: 2, price: 75, avail: false, emoji: '🏨' },
        ].map((h, i) => (
          <div data-dg-component="hotelCard" key={i} className={`bg-white rounded-[18px] p-4 mb-3 shadow-sm ${h.avail ? '' : 'opacity-50'}`}>
            <div className="flex gap-3.5 items-center">
              <div className="w-[52px] h-[52px] bg-slate-100 rounded-[14px] flex items-center justify-center text-[28px]">{h.emoji}</div>
              <div className="flex-1">
                <div className="text-[15px] font-bold text-slate-900">{h.name}</div>
                <div className="text-xs text-amber-400 mt-0.5">{'⭐'.repeat(h.stars)}</div>
              </div>
              <div className="text-right">
                <div className="text-base font-extrabold text-slate-900">${h.price}</div>
                <div className="text-[10px] text-slate-400">/night</div>
              </div>
            </div>
            <button disabled={!h.avail} className={`w-full mt-3 border-none rounded-xl py-[11px] text-[13px] font-bold ${h.avail ? 'bg-gradient-to-br from-sky-500 to-indigo-500 text-white cursor-pointer' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}>
              {h.avail ? '✓ Book Now' : 'Unavailable'}
            </button>
          </div>
        ))}

        {/* Budget Tab */}
        {tab === 'budget' && (
          <>
            <div data-dg-component="budgetSummary" className="bg-gradient-to-br from-sky-500 to-indigo-500 rounded-[20px] p-5 mb-3.5 text-white">
              <div className="text-[13px] opacity-80 mb-1">Total Budget</div>
              <div className="text-[32px] font-extrabold mb-3">${totalBudget.toLocaleString()}</div>
              <div className="h-2 bg-white/20 rounded-full">
                <div className="h-full bg-white rounded-full" style={{ width: `${(totalSpent / totalBudget) * 100}%` }} />
              </div>
              <div className="flex justify-between mt-2 text-[13px]">
                <span>Spent: ${totalSpent.toLocaleString()}</span>
                <span>Remaining: ${remaining.toLocaleString()}</span>
              </div>
            </div>
            {expenses.map(e => (
              <div data-dg-component="expenseItem" key={e.id} className="bg-white rounded-2xl px-4 py-3.5 mb-2.5 flex items-center gap-3.5 shadow-sm">
                <div className="text-2xl">{e.cat}</div>
                <div className="flex-1 text-sm font-semibold text-slate-900">{e.label}</div>
                <div className="text-[15px] font-bold text-slate-900">${e.amount}</div>
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  );
}
